    #[tokio::test]
    async fn test_client_basic() {
        let router = Router::new()
            .get("/", || async { "hello" });

        let client = TestClient::new(router);
        let response = client.get("/").send().await;

        response.assert_status(200);
        response.assert_body_eq("hello");
    }

    #[tokio::test]
    async fn test_client_json() {
        #[derive(Serialize, Deserialize, PartialEq, Debug)]
        struct User { name: String }

        let router = Router::new()
            .post("/users", |Json(user): Json<User>| async move {
                Json(user)
            });

        let client = TestClient::new(router);
        let response = client
            .post("/users")
            .json(&User { name: "Alice".into() })
            .send()
            .await;

        response.assert_status(200);
        response.assert_json(&User { name: "Alice".into() });
    }

    #[test]
